DROP TRIGGER IF EXISTS tbiu_sc_fin_counter_cash_tran ON sc_fin_counter_cash_tran CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_fin_counter_cash_tran() RETURNS trigger AS $BODY$
BEGIN
  --Validate
  if NEW.coin25s < 0 or NEW.coin50s < 0 or NEW.coin1b < 0 or NEW.coin2b < 0 or NEW.coin5b < 0 or NEW.coin10b < 0
    or NEW.bn20 < 0 or NEW.bn50 < 0 or NEW.bn100 < 0 or NEW.bn500 < 0 or NEW.bn1000 < 0 then
    CALL spa_dberror('จำนวนเหรียญหรือจำนวนธนบัตร ไม่สามารถติดลบได้');
  end if;

  -- Default
  if coalesce(NEW.coin25s::text, '') = '' then NEW.coin25s :=0;end if;
  if coalesce(NEW.coin50s::text, '') = '' then NEW.coin50s :=0;end if;
  if coalesce(NEW.coin1b::text, '') = '' then NEW.coin1b :=0;end if;
  if coalesce(NEW.coin2b::text, '') = ''  then NEW.coin2b :=0;end if;
  if coalesce(NEW.coin5b::text, '') = '' then NEW.coin5b :=0;end if;
  if coalesce(NEW.coin10b::text, '') = '' then NEW.coin10b :=0;end if;
  if coalesce(NEW.bn20::text, '') = '' then NEW.bn20 :=0;end if;
  if coalesce(NEW.bn50::text, '') = '' then NEW.bn50 :=0;end if;
  if coalesce(NEW.bn100::text, '') = '' then NEW.bn100 :=0;end if;
  if coalesce(NEW.bn500::text, '') = '' then NEW.bn500 :=0;end if;
  if coalesce(NEW.bn1000::text, '') = '' then NEW.bn1000 :=0;end if;

  -- Entry
  if (coalesce(OLD.branch_fin::text, '') = '' and  (NEW.branch_fin IS NOT NULL AND NEW.branch_fin::text <> '')) then
    if (pka.auto_entry) then
       NEW.entry_date   := statement_timestamp();
       NEW.entry_branch := current_setting('app.login_br', true);
       NEW.entry_client := pka_com_login.login_pc;
    end if;
  end if;

  -- Auto seq_no
  if (pka.auto_seqno) then
    if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
      select  max(seq_no) into STRICT NEW.seq_no
      from sc_fin_counter_cash_tran
      where ( branch_fin = NEW.branch_fin )
      and (journal_date = NEW.journal_date)
      and (entry_fin = NEW.entry_fin)
      and (open_no = NEW.open_no);
      if NEW.seq_no > 0 then
        NEW.seq_no  := NEW.seq_no + 1;
      else
        NEW.seq_no := 1;
      end if;
    end if;
  end if;
RETURN NEW;
end
$BODY$
 LANGUAGE 'plpgsql' SECURITY DEFINER;
